noncompliant:
try
{
    DoSomething();
}
catch (Exception ex)
{
    logger.LogError(ex, "An error occurred");
    throw; // Noncompliant - exception logged AND rethrown, will be logged twice
}

catch (InvalidOperationException ex)
{
    Log(ex.Message);
    throw ex; // Noncompliant - both logged and rethrown
}

compliant:
try
{
    DoSomething();
}
catch (Exception ex)
{
    logger.LogError(ex, "An error occurred");
    // Handle the exception, don't rethrow
}

try
{
    DoSomething();
}
catch (Exception ex)
{
    // Rethrow without logging
    throw;
}

try
{
    DoSomething();
}
catch (Exception ex)
{
    logger.LogError("An error occurred"); // Log without exception details
    throw; // Compliant - exception not included in log
}
